import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is sample size?", a: "Sample size is the number of people, observations, or data points included in a study. A larger sample usually gives more reliable estimates, especially when the population is large or the desired margin of error is small." },
  { q: "How do you calculate sample size?", a: "For proportions, sample size is commonly estimated with n = z^2 x p(1-p) / e^2. This calculator uses p = 0.5 for a conservative estimate and applies finite population correction when a population size is provided." },
  { q: "What is margin of error?", a: "Margin of error is the expected range around a survey result. A 5% margin of error means the real population value is likely within 5 percentage points of the sample estimate at the selected confidence level." },
  { q: "How does confidence level affect sample size?", a: "Higher confidence levels require larger samples because they use a larger z-score. For the same margin of error, 99% confidence needs more responses than 95% confidence." },
  { q: "What happens if your sample size is too small?", a: "A small sample can produce unstable results, wide confidence intervals, and conclusions that do not represent the population well. It also increases the risk of missing real differences." },
];

type Mode = "sample" | "margin";
const zScores: Record<string, number> = { "90": 1.645, "95": 1.96, "99": 2.576 };
const fmt = (value: number) => Number.isFinite(value) ? Number(value.toFixed(4)).toLocaleString() : "Invalid";

export default function SampleSizeCalculator() {
  const [mode, setMode] = useState<Mode>("sample");
  const [confidence, setConfidence] = useState("95");
  const [margin, setMargin] = useState(5);
  const [population, setPopulation] = useState(10000);
  const [sample, setSample] = useState(385);
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

  const result = useMemo(() => {
    const z = zScores[confidence];
    const p = 0.5;
    if (mode === "sample") {
      const e = margin / 100;
      if (e <= 0 || population <= 0) return { label: "Invalid input", value: "Use positive margin and population.", step: "Margin of error and population must be positive." };
      const infinite = (z * z * p * (1 - p)) / (e * e);
      const adjusted = infinite / (1 + (infinite - 1) / population);
      return { label: "Required Sample Size", value: Math.ceil(adjusted).toLocaleString(), step: `n0 = ${z}^2 x 0.5 x 0.5 / ${e}^2 = ${fmt(infinite)}. Adjusted n = n0 / (1 + (n0 - 1) / ${population}) = ${fmt(adjusted)}.` };
    }
    if (sample <= 0 || population <= 0) return { label: "Invalid input", value: "Use positive sample and population.", step: "Sample size and population must be positive." };
    const fpc = Math.sqrt((population - sample) / Math.max(population - 1, 1));
    const e = z * Math.sqrt((p * (1 - p)) / sample) * (sample < population ? fpc : 1);
    return { label: "Margin of Error", value: `${fmt(e * 100)}%`, step: `e = ${z} x sqrt(0.5 x 0.5 / ${sample})${sample < population ? ` x finite population correction` : ""} = ${fmt(e * 100)}%.` };
  }, [mode, confidence, margin, population, sample]);

  return (
    <>
      <SEOHead title="Free Sample Size Calculator Online - Calculate Required Sample Size Instantly | CalcHive" description="Free online sample size calculator. Calculate required sample size for any study based on confidence level, margin of error and population size instantly. 100% free for researchers, no signup required." canonical="/sample-size-calculator" keywords="free sample size calculator, sample size calculator online free, calculate sample size free, margin of error calculator free, confidence interval sample size calculator free" category="Statistics Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Sample Size Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Use this sample size calculator online free to calculate sample size free or estimate margin of error for a study.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div><label htmlFor="mode" className="text-sm font-semibold text-foreground block mb-2">Mode</label><select id="mode" value={mode} onChange={(event) => setMode(event.target.value as Mode)} className={inputClass}><option value="sample">Calculate required sample size</option><option value="margin">Calculate margin of error</option></select></div>
            <div><label htmlFor="confidence" className="text-sm font-semibold text-foreground block mb-2">Confidence level</label><select id="confidence" value={confidence} onChange={(event) => setConfidence(event.target.value)} className={inputClass}><option value="90">90%</option><option value="95">95%</option><option value="99">99%</option></select></div>
            <div><label htmlFor="population" className="text-sm font-semibold text-foreground block mb-2">Population size</label><input id="population" type="number" inputMode="numeric" value={population} onChange={(event) => setPopulation(Number(event.target.value))} className={inputClass} /></div>
            {mode === "sample" ? <div><label htmlFor="margin" className="text-sm font-semibold text-foreground block mb-2">Margin of error (%)</label><input id="margin" type="number" inputMode="decimal" step="0.1" value={margin} onChange={(event) => setMargin(Number(event.target.value))} className={inputClass} /></div> : <div><label htmlFor="sample" className="text-sm font-semibold text-foreground block mb-2">Sample size</label><input id="sample" type="number" inputMode="numeric" value={sample} onChange={(event) => setSample(Number(event.target.value))} className={inputClass} /></div>}
          </div>
          <motion.div key={`${mode}-${confidence}-${margin}-${population}-${sample}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">{result.label}</p><p className="text-5xl font-black text-white tracking-tight" data-testid="result-sample-size">{result.value}</p></div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Step by step</p><p className="text-sm text-foreground" data-testid="result-steps">{result.step}</p></div>
          </motion.div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Sample Size for Any Study for Free</h2><p className="text-muted-foreground leading-relaxed">Choose a confidence level, margin of error, and population size. This confidence interval sample size calculator free tool estimates the required responses.</p>
          <h2 className="text-2xl font-bold text-foreground">How Confidence Level and Margin of Error Affect Sample Size</h2><p className="text-muted-foreground leading-relaxed">Higher confidence and lower margin of error both increase required sample size because the estimate must be more precise.</p>
          <h2 className="text-2xl font-bold text-foreground">Free Research Sample Size Tool for Students and Researchers</h2><p className="text-muted-foreground leading-relaxed">Use this margin of error calculator free for surveys, classroom research, academic projects, and planning data collection.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/sample-size-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


